import tensorflow as tf

# Warmup + decay schedule
def warmup_decay_schedule(step, warmup_steps, total_steps, lr_initial, lr_target):
    if step < warmup_steps:
        # Linear warmup
        return lr_initial + (step / warmup_steps) * (lr_target - lr_initial)
    else:
        # Polynomial decay
        decay_steps = total_steps - warmup_steps
        return tf.keras.optimizers.schedules.PolynomialDecay(
            lr_target, decay_steps, end_learning_rate=lr_initial * 0.01
        )(step - warmup_steps)

# Create optimizer with learning rate schedule
lr_schedule = lambda step: warmup_decay_schedule(
    step,
    warmup_steps=1000,
    total_steps=10000,
    lr_initial=1e-8,
    lr_target=1e-3
)

optimizer = tf.keras.optimizers.Adam(learning_rate=lr_schedule)

model.fit(train_data, train_labels, epochs=100, optimizer=optimizer)

from tensorflow.keras.optimizers.schedules import CosineDecay

total_steps = 10000
warmup_steps = 1000
lr_target = 0.001

def cosine_with_warmup(step):
    if step < warmup_steps:
        # Linear warmup
        return (step / warmup_steps) * lr_target
    else:
        # Cosine decay
        decay_steps = total_steps - warmup_steps
        return CosineDecay(
            lr_target, decay_steps, alpha=0.01
        )(step - warmup_steps)

optimizer = tf.keras.optimizers.Adam(learning_rate=cosine_with_warmup)
